  return (
    <div>
      <AiFillStar r color={selected ? "red" : "grey"} />
      <AiFillStar color="#b9c0c7" size={"30px"} />
      <AiFillStar color="#b9c0c7" size={"30px"} />
      <AiFillStar color="#b9c0c7" size={"30px"} />
      <AiFillStar color="#b9c0c7" size={"30px"} />
    </div>
  );
};

export default Stars;
